  const subject = subjectTemplate.replace(/\{\{first_name\}\}/g, firstName).replace(/\{\{city\}\}/g, city);
  const previewText = nl.preview_text.replace(/\{\{first_name\}\}/g, firstName).replace(/\{\{city\}\}/g, city);
  const introText = nl.intro_text.replace(/\{\{first_name\}\}/g, firstName).replace(/\{\{city\}\}/g, city);
  const textBody = nl.textBody.replace(/\{\{first_name\}\}/g, firstName).replace(/\{\{city\}\}/g, city);

  // Build inner HTML sections
  let innerHtml = '';

  // 1. Newsletter badge
  innerHtml += newsletterBadge(monthName, year.toString());

  // 2. Headline + intro
  innerHtml += newsletterIntro(nl.headline, introText);

  // 3. Content section (seasonal tips)
  innerHtml += contentSection(nl.content_html.replace(/\{\{first_name\}\}/g, firstName).replace(/\{\{city\}\}/g, city));

  // 4. Spotlight section (if applicable)
  if (nl.spotlight && nl.spotlight.show) {
    innerHtml += spotlightSection(nl.spotlight.name, nl.spotlight.city || city, nl.spotlight.story);
  }

  // 5. Offer section
  if (nl.offer && nl.offer.show) {
    const offerText = nl.offer.text.replace(/\{\{first_name\}\}/g, firstName).replace(/\{\{city\}\}/g, city);
    innerHtml += offerBox(nl.offer.headline, offerText, nl.offer.cta_text, nl.offer.cta_url);
  }

  // 6. Local events section
  if (nl.local && nl.local.show) {
    innerHtml += localEventsSection(nl.local.headline, nl.local.text);
  }

  // 7. Review block
  innerHtml += reviewBlock(nl.review.text, nl.review.name);

  // 8. Quick links bar (Book, Refer, Review, Call)
  innerHtml += quickLinksBar();

  const htmlBody = buildHtml({ previewText: previewText, innerHtml: innerHtml });

  results.push({
    json: {
      email: c.email,
      first_name: firstName,
      subject: subject,
      body: textBody,
      htmlBody: htmlBody,
      emailType: nl.emailType,
      _skip: false
    }
  });
}
return results.length > 0 ? results : [{ json: { _skip: true } }];
